def forward(self, x, padding_mask=None, layer=None, corpus_key=None):
    x, layer_results = self.extract_features(
        x, padding_mask, layer, corpus_key=corpus_key
    )

    if self.layer_norm_first and layer is None:
        x = self.layer_norm(x)

    return x, layer_results

def extract_features(
    self,
    x,
    padding_mask=None,
    tgt_layer=None,
    min_layer=0,
    corpus_key=None,
):

    if padding_mask is not None:
        x = index_put(x, padding_mask, 0)

    x_conv = self.pos_conv(x.transpose(1, 2))
    x_conv = x_conv.transpose(1, 2)
    x = x + x_conv

    if not self.layer_norm_first:
        x = self.layer_norm(x)

    # pad to the sequence length dimension
    x, pad_length = pad_to_multiple(
        x, self.required_seq_len_multiple, dim=-2, value=0
    )
    if pad_length > 0 and padding_mask is None:
        padding_mask = x.new_zeros((x.size(0), x.size(1)), dtype=torch.bool)
        padding_mask[:, -pad_length:] = True
    else:
        padding_mask, _ = pad_to_multiple(
            padding_mask, self.required_seq_len_multiple, dim=-1, value=True
        )
    x = F.dropout(x, p=self.dropout, training=self.training)

    # B x T x C -> T x B x C
    x = x.transpose(0, 1)

    layer_results = []
    r = None

    for i, layer in enumerate(self.layers):
        dropout_probability = np.random.random() if self.layerdrop > 0 else 1
        if not self.training or (dropout_probability > self.layerdrop):
            layer_check = layer
            if isinstance(layer, FullyShardedDataParallel):
                layer_check = layer.unwrapped_module
            if (corpus_key is None) or (
                not isinstance(layer_check, (
                    TransformerSentenceEncoderWithAdapterLayer,
                    )
                )
            ):
                x, (z, lr) = layer(
                    x, self_attn_padding_mask=padding_mask, need_weights=False
                )
            else:
                x, (z, lr) = layer(
                    x,
                    self_attn_padding_mask=padding_mask,
                    need_weights=False,
                    corpus_key=corpus_key,
                )
            if i >= min_layer:
                layer_results.append((x, z, lr))
        if i == tgt_layer:
            r = x
            break

    if r is not None:
        x = r

    # T x B x C -> B x T x C
    x = x.transpose(0, 1)

    # undo paddding
    if pad_length > 0:
        x = x[:, :-pad_length]

        def undo_pad(a, b, c):
            return (
                a[:-pad_length],
                b[:-pad_length] if b is not None else b,
                c[:-pad_length],
            )

        layer_results = [undo_pad(*u) for u in layer_results]

    return x, layer_results

def max_positions(self):
    """Maximum output length supported by the encoder."""
    return self.args.max_positions

def _conv_out_length(input_length, kernel_size, stride):
    return torch.floor((input_length - kernel_size) / stride + 1)

def block(
    n_in,
    n_out,
    k,
    stride,
    is_layer_norm=False,
    is_group_norm=False,
    conv_bias=False,
):
    def make_conv():
        conv = nn.Conv1d(n_in, n_out, k, stride=stride, bias=conv_bias)
        nn.init.kaiming_normal_(conv.weight)
        return conv

    assert (
        is_layer_norm and is_group_norm
    ) == False, "layer norm and group norm are exclusive"

    if is_layer_norm:
        return nn.Sequential(
            make_conv(),
            nn.Dropout(p=dropout),
            nn.Sequential(
                TransposeLast(),
                Fp32LayerNorm(dim, elementwise_affine=True),
                TransposeLast(),
            ),
            nn.GELU(),
        )
    elif is_group_norm:
        return nn.Sequential(
            make_conv(),
            nn.Dropout(p=dropout),
            Fp32GroupNorm(dim, dim, affine=True),
            nn.GELU(),
        )
    else:
        return nn.Sequential(make_conv(), nn.Dropout(p=dropout), nn.GELU())

    def make_conv():
        conv = nn.Conv1d(n_in, n_out, k, stride=stride, bias=conv_bias)
        nn.init.kaiming_normal_(conv.weight)
        return conv

def get_extra_losses(self, net_output):
    pen = []

    if "prob_perplexity" in net_output:
        pen.append(
            (net_output["num_vars"] - net_output["prob_perplexity"])
            / net_output["num_vars"]
        )

    if "features_pen" in net_output:
        pen.append(net_output["features_pen"])

    return pen

def remove_pretraining_modules(self, last_layer=None):
    self.quantizer = None
    self.project_q = None
    self.target_glu = None
    self.final_proj = None

    if last_layer is not None:
        self.encoder.layers = nn.ModuleList(
            l for i, l in enumerate(self.encoder.layers) if i <= last_layer
        )

def __init__(
    self,
    conv_layers: List[Tuple[int, int, int]],
    dropout: float = 0.0,
    mode: str = "default",
    conv_bias: bool = False,
):
    super().__init__()

    assert mode in {"default", "layer_norm"}

    def block(
        n_in,
        n_out,
        k,
        stride,
        is_layer_norm=False,
        is_group_norm=False,
        conv_bias=False,
    ):
        def make_conv():
            conv = nn.Conv1d(n_in, n_out, k, stride=stride, bias=conv_bias)
            nn.init.kaiming_normal_(conv.weight)
            return conv

        assert (
            is_layer_norm and is_group_norm
        ) == False, "layer norm and group norm are exclusive"

        if is_layer_norm:
            return nn.Sequential(
                make_conv(),
                nn.Dropout(p=dropout),
                nn.Sequential(
                    TransposeLast(),
                    Fp32LayerNorm(dim, elementwise_affine=True),
                    TransposeLast(),
                ),
                nn.GELU(),
            )
        elif is_group_norm:
            return nn.Sequential(
                make_conv(),
                nn.Dropout(p=dropout),
                Fp32GroupNorm(dim, dim, affine=True),
                nn.GELU(),
            )
        else:
            return nn.Sequential(make_conv(), nn.Dropout(p=dropout), nn.GELU())

    in_d = 1
    self.conv_layers = nn.ModuleList()
    for i, cl in enumerate(conv_layers):
        assert len(cl) == 3, "invalid conv definition: " + str(cl)
        (dim, k, stride) = cl

        self.conv_layers.append(
            block(
                in_d,
                dim,
                k,
                stride,
                is_layer_norm=mode == "layer_norm",
                is_group_norm=mode == "default" and i == 0,
                conv_bias=conv_bias,
            )
        )
        in_d = dim

def extract_features(
    self, source, padding_mask, mask=False, layer=None, corpus_key=None
):
    res = self.forward(
        source,
        padding_mask,
        mask=mask,
        features_only=True,
        layer=layer,
        corpus_key=corpus_key,
    )
    return res

def get_logits(self, net_output):
    logits = net_output["x"]
    logits = logits.transpose(0, 2)
    logits = logits.reshape(-1, logits.size(-1))
    return logits

def get_targets(self, sample, net_output, expand_steps=True):
    x = net_output["x"]
    return x.new_zeros(x.size(1) * x.size(2), dtype=torch.long)

